<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Événements en France</title>
  <link href="https://fonts.googleapis.com/css2?family=Sora&display=swap" rel="stylesheet" />
  <link rel="stylesheet" href="/style.css">
  <style>
/* ---------- Base ---------- */
body {
  font-family: 'Sora', sans-serif;
  background: #fff5eb;
  margin: 0;
  padding: 0;
  width: 100%;
}

main {
  padding: 15px;
}

h1 {
  text-align: left;
  margin-bottom: 15px;
  color: #BC163A;
  font-weight: 700;
  font-size: 28px;
}

.titre {
  text-align: center;
  padding: 30px 10px;
}

p {
  text-align: left;
  font-style: italic;
  color: #888;
}

/* ---------- Layout principal ---------- */
.map-and-events {
  display: flex;
  align-items: flex-start;
  gap: 40px;
}

.left-column {
  flex-shrink: 0;
  max-width: 600px;
}

.right-column {
  display: flex;
  flex-direction: column;
  margin-left: auto;
  max-width: 800px;
  width: 100%;
}

/* ---------- Barre de filtres ---------- */
#filtersBar {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-start;
  margin-bottom: 30px;
}

.filter-group {
  display: flex;
  align-items: center;
  background-color: #7D6852;
  padding: 4px 10px;
  border-radius: 16px;
  min-width: max-content;
}

label {
  font-weight: 600;
  color: #fff5eb;
  margin-right: 6px;
  font-size: 13px;
}

#searchInput,
select {
  font-size: 14px;
  border: none;
  border-radius: 16px;
  outline: none;
  transition: box-shadow 0.3s ease;
  background-color: #7D6852;
}

#searchInput {
  padding: 6px 12px;
  color: #000;
  width: 200px;
}

#searchInput::placeholder {
  color: #000000a0;
}

#searchInput:focus,
select:focus {
  box-shadow: 0 0 6px #fff5eb;
}

select {
  padding: 5px 10px;
  color: #fff5eb;
  cursor: pointer;
  appearance: none;
  background-image: url("data:image/svg+xml;charset=US-ASCII,%3csvg%20width%3d%2210%22%20height%3d%227%22%20viewBox%3d%220%200%2010%207%22%20xmlns%3d%22http%3a//www.w3.org/2000/svg%22%3e%3cpolygon%20points%3d%220%200%205%207%2010%200%22%20fill%3d%22%23fff5eb%22/%3e%3c/svg%3e");
  background-repeat: no-repeat;
  background-position: right 10px center;
  background-size: 10px 7px;
}

/* ---------- Événements ---------- */
#eventsContainer {
  max-width: 1100px;
}

.event-card {
  display: flex;
  background: transparent;
  border-radius: 8px;
  margin-bottom: 20px;
  align-items: center;
  overflow: hidden;
}

.event-image {
  width: 200px;
  height: 170px;
  object-fit: cover;
  flex-shrink: 0;
  border-radius: 12px;
}

.event-details {
  padding: 15px 20px;
  flex-grow: 1;
  color: #BC163A;
  text-align: left;
}

.event-title {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 8px;
}

.event-info {
  font-size: 14px;
  margin-bottom: 5px;
}

.event-info strong {
  color: #BC163A;
}

/* ---------- Carte de France ---------- */
#france-map-container {
  margin: 30px 0;
  position: relative;
  max-width: 600px;
}

#france-map {
  width: 100%;
  height: auto;
}

.region-path {
  fill: #FFD9A8;
  stroke: white;
  stroke-width: 5;
  transition: transform 0.3s ease, filter 0.3s ease;
  cursor: pointer;
  transform-origin: center;
}

.region-path:hover {
  fill: #BC163A;
  transform: scale(1.1);
  filter: drop-shadow(0 4px 6px rgba(0, 0, 0, 0.3));
}

/* ---------- Tooltip événement ---------- */
#region-events-tooltip {
  position: absolute;
  background: #fff5eb;
  border: 2px solid #BC163A;
  border-radius: 8px;
  padding: 10px;
  max-width: 300px;
  display: none;
  z-index: 100;
  box-shadow: 0 4px 8px rgba(0,0,0,0.2);
}

.tooltip-title {
  font-weight: bold;
  color: #BC163A;
  margin-bottom: 5px;
}

.tooltip-event {
  margin-bottom: 5px;
  font-size: 14px;
}

/* ---------- Carte + Mascotte ---------- */
.carte-container {
  position: relative;
  transform: translate(500px, 400px) scale(0.8);
  transform-origin: bottom right;
}

.carte {
  background-color: #b91939;
  color: white;
  padding: 48px;
  border-radius: 24px;
  max-width: 600px;
  font-size: 20px;
  font-weight: 600;
  line-height: 1.7;
  box-shadow: 0 12px 30px rgba(0, 0, 0, 0.2);
  margin-top: 20px;
  position: relative;
  overflow: visible;
}

.mascotte {
  position: absolute;
  right: -170px;
  bottom: -35px;
  width: 240px;
  height: auto;
  align-self: center;
  margin-top: 30px;
}

/* ---------- Responsive ---------- */
@media (max-width: 900px) {
  .map-and-events {
    flex-direction: column;
    align-items: center;
  }

  .right-column {
    margin-left: 0;
    width: 100%;
  }

  .carte-container {
    transform: none;
    margin-top: 40px;
  }

  .mascotte {
    position: static;
    margin: 20px auto 0;
    display: block;
  }
}

  </style>
</head>

